3374 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3375                                                FPClassTest DemandedMask,
3376                                                KnownFPClass &Known,
3377                                                unsigned Depth) {
3378   Use &U = I->getOperandUse(OpNo);
3379   Value *V = U.get();
3380   Type *VTy = V->getType();
3381 
3382   if (DemandedMask == fcNone) {
3383     if (isa<UndefValue>(V))
3384       return false;
3385     replaceUse(U, PoisonValue::get(VTy));
3386     return true;
3387   }
3388 
3389   // Handle constant
3390   Instruction *VInst = dyn_cast<Instruction>(V);
3391   if (!VInst) {
3392     // Handle constants and arguments
3393     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3394     Known.knownNot(~DemandedMask);
3395 
3396     if (Known.KnownFPClasses == fcNone) {
3397       if (isa<UndefValue>(V))
3398         return false;
3399       replaceUse(U, PoisonValue::get(VTy));
3400       return true;
3401     }
3402 
3403     // Do not try to replace values which are already constants (unless we are
3404     // folding to poison). Doing so could promote poison elements to non-poison
3405     // constants.
3406     if (isa<Constant>(V))
3407       return false;
3408 
3409     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3410     if (!FoldedToConst || FoldedToConst == V)
3411       return false;
3412 
3413     replaceUse(U, FoldedToConst);
3414     return true;
3415   }
3416 
3417   if (Depth == MaxAnalysisRecursionDepth)
3418     return false;
3419 
3420   Value *NewVal;
3421 
3422   if (VInst->hasOneUse()) {
3423     // If the instruction has one use, we can directly simplify it.
3424     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3425   } else {
3426     // If there are multiple uses of this instruction, then we can simplify
3427     // VInst to some other value, but not modify the instruction.
3428     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3429                                                 Depth);
3430   }
3431 
3432   if (!NewVal)
3433     return false;
3434   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3435     salvageDebugInfo(*OpInst);
3436 
3437   replaceUse(U, NewVal);
3438   return true;
3439 }
