3262 Value *InstCombinerImpl::SimplifyMultipleUseDemandedFPClass(
3263     Instruction *I, FPClassTest DemandedMask, KnownFPClass &Known,
3264     Instruction *CxtI, unsigned Depth) {
3265   FastMathFlags FMF;
