3276         computeKnownFPClass(I->getOperand(2), DemandedMask, CxtI, Depth + 1);
3277     if (KnownRHS.isKnownNever(DemandedMask))
3278       return I->getOperand(1);
3279 
3280     KnownFPClass KnownLHS =
3281         computeKnownFPClass(I->getOperand(1), DemandedMask, CxtI, Depth + 1);
3282     if (KnownLHS.isKnownNever(DemandedMask))
3283       return I->getOperand(2);
3284 
3285     adjustKnownFPClassForSelectArm(KnownLHS, I->getOperand(0), I->getOperand(1),
3286                                    /*Invert=*/false, SQ, Depth);
3287     adjustKnownFPClassForSelectArm(KnownRHS, I->getOperand(0), I->getOperand(2),
3288                                    /*Invert=*/true, SQ, Depth);
3289     Known = KnownLHS.intersectWith(KnownRHS);
3290     Known.knownNot(~DemandedMask);
3291     break;
3292   }
3293   case Instruction::FNeg: {
3294     // Special case fneg(fabs(x))
3295     Value *Src;
3296 
3297     Value *FNegSrc = I->getOperand(0);
3298     if (!match(FNegSrc, m_FAbs(m_Value(Src)))) {
3299       Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3300       break;
3301     }
3302 
3303     FastMathFlags FabsFMF = cast<FPMathOperator>(FNegSrc)->getFastMathFlags();
3304     FPClassTest ThisDemandedMask =
3305         adjustDemandedMaskFromFlags(DemandedMask, FabsFMF);
3306 
3307     KnownFPClass KnownSrc =
3308         computeKnownFPClass(Src, fcAllFlags, CxtI, Depth + 1);
